class DSU:
    def __init__(self, n):
        self.parent = list(range(n))
        self.rank = [0] * n

    def find(self, i):
        if self.parent[i] == i:
            return i
        self.parent[i] = self.find(self.parent[i])
        return self.parent[i]

    def union(self, i, j):
        root_i = self.find(i)
        root_j = self.find(j)

        if root_i != root_j:
            if self.rank[root_i] < self.rank[root_j]:
                self.parent[root_i] = root_j
            elif self.rank[root_i] > self.rank[root_j]:
                self.parent[root_j] = root_i
            else:
                self.parent[root_j] = root_i
                self.rank[root_i] += 1
            return True
        return False

def minCostConnectCities(n, connections):
    if n <= 1:
        return 0

    connections.sort(key=lambda x: x[2])

    dsu = DSU(n)
    min_cost = 0
    num_edges_connected = 0

    for city1, city2, cost in connections:
        if dsu.union(city1, city2):
            min_cost += cost
            num_edges_connected += 1

    if num_edges_connected == n - 1:
        return min_cost
    else:
        return -1
